/**
 * MedX header layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Top bar height, breadcrumbs slot, and actions.
 */
const HEADER_TOKENS = Object.freeze({
  primary: { value: "layout-header-primary", scope: "layout" },
  secondary: { value: "layout-header-secondary", scope: "layout" },
  muted: { value: "layout-header-muted", scope: "layout" },
  accent: { value: "layout-header-accent", scope: "layout" },
  surface: { value: "layout-header-surface", scope: "layout" },
});

const HEADER_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const HEADER_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const headerRegistry = new Map();
const HEADER_listeners = new Set();
let HEADER_seq = 0;

function createHeaderId(prefix = "medx-layout-header") {
  HEADER_seq += 1;
  return `${prefix}-${HEADER_seq}`;
}

function registerHeader(config = {}) {
  const entryId = config.id ?? createHeaderId();
  const preset = HEADER_PRESETS[config.preset ?? "default"] ?? HEADER_PRESETS.default;
  const token = HEADER_TOKENS[config.token ?? preset.token] ?? HEADER_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: HEADER_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  headerRegistry.set(entryId, entry);
  notifyHeaderListeners("register", entry);
  return entry;
}

function updateHeader(id, patch = {}) {
  const entry = headerRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyHeaderListeners("update", entry);
  return entry;
}

function resolveHeader(id) {
  const entry = headerRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listHeaderEntries(filter = {}) {
  let items = Array.from(headerRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onHeaderEvent(listener) {
  HEADER_listeners.add(listener);
  return () => HEADER_listeners.delete(listener);
}

function notifyHeaderListeners(type, entry) {
  for (const listener of HEADER_listeners) {
    try {
      listener({ type, entry, registrySize: headerRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:header] listener error", err.message);
    }
  }
}

function getHeaderMetrics() {
  const items = listHeaderEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(HEADER_TOKENS).length,
    presets: Object.keys(HEADER_PRESETS).length,
  };
}

async function runMedxHeader() {
  console.log("[medx:ui:layout:header] runtime initialized");
  console.log(`[medx:ui:layout:header] tokens=${Object.keys(HEADER_TOKENS).length} presets=${Object.keys(HEADER_PRESETS).length}`);

  const events = [];
  onHeaderEvent((e) => events.push(e.type));

  const domains = Object.keys(HEADER_SUPPLY_CHAIN);
  const presets = Object.keys(HEADER_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerHeader({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/header" },
    });
  }

  const first = listHeaderEntries()[0];
  if (first) updateHeader(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getHeaderMetrics();
  const resolved = first ? resolveHeader(first.id) : null;

  console.log(`[medx:ui:layout:header] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:header] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:header] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:header] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:header] bootstrap complete");
}

module.exports = runMedxHeader;
